import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { useNavigate } from "react-router-dom";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:wght@300;400;500&display=swap');

  :root {
    --bg: #f5f0e8;
    --surface: #faf7f2;
    --border: #e2d9cc;
    --ink: #1a1612;
    --ink-muted: #7a6f63;
    --accent: #c8441a;
    --accent-hover: #a83515;
    --shadow: 0 2px 12px rgba(26,22,18,0.07);
    --radius: 10px;
    --transition: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  }

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  .profile-root {
    min-height: 100vh;
    background: var(--bg);
    font-family: 'DM Sans', sans-serif;
    color: var(--ink);
    padding: 80px 24px 80px;
  }

  .profile-inner {
    max-width: 680px;
    margin: 0 auto;
  }

  .profile-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    margin-bottom: 48px;
    padding-bottom: 20px;
    border-bottom: 1.5px solid var(--border);
  }

  .profile-header h2 {
    font-family: 'Playfair Display', serif;
    font-size: 2.2rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1;
    color: var(--ink);
  }

  .profile-header .dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: var(--accent);
  }

  .section-label {
    font-size: 0.7rem;
    font-weight: 500;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--ink-muted);
    margin-bottom: 16px;
  }

  .create-section {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: var(--radius);
    padding: 28px;
    margin-bottom: 48px;
    box-shadow: var(--shadow);
  }

  .form-group {
    display: flex;
    flex-direction: column;
    gap: 10px;
    margin-bottom: 14px;
  }

  .form-field {
    width: 100%;
    background: var(--bg);
    border: 1.5px solid var(--border);
    border-radius: 7px;
    padding: 11px 14px;
    font-family: inherit;
  }

  .btn-create {
    background: var(--accent);
    color: #fff;
    border: none;
    border-radius: 7px;
    padding: 11px 22px;
    cursor: pointer;
    font-weight: 500;
    transition: background var(--transition);
  }

  .btn-create:hover { background: var(--accent-hover); }

  .projects-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  .project-card {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: var(--radius);
    padding: 20px 24px;
    cursor: pointer;
    position: relative;
    transition: transform var(--transition);
  }
  
  .project-card:hover { transform: translateY(-2px); }
  
  .delete-btn {
    position: absolute;
    top: 15px;
    right: 15px;
    background: #fceae8;
    color: var(--accent);
    border: 1px solid #f1cfc8;
    border-radius: 6px;
    padding: 4px 10px;
    font-size: 0.75rem;
    cursor: pointer;
    z-index: 10;
  }

  .delete-btn:hover { background: var(--accent); color: white; }
`;

export default function Profile() {
  const [user, setUser] = useState(null);
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");

  const navigate = useNavigate();

  useEffect(() => {
    getUser();
  }, []);

  const getUser = async () => {
    try {
      const { data: { user }, error } = await supabase.auth.getUser();
      if (error) throw error;
      
      setUser(user);
      if (user) await fetchProjects(user.id);
    } catch (err) {
      console.error("Error fetching user:", err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchProjects = async (userId) => {
    const { data, error } = await supabase
      .from("projects")
      .select("*")
      .eq("user_id", userId)
      .order("created_at", { ascending: false });

    if (error) console.error("Error fetching projects:", error.message);
    else setProjects(data || []);
  };

  const createProject = async () => {
    if (!user) return alert("You must be logged in");
    if (!title.trim()) return alert("Enter project title");

    const { data, error } = await supabase
      .from("projects")
      .insert([{ user_id: user.id, title, description }])
      .select(); // returns the created object

    if (error) {
      alert(error.message);
    } else {
      setProjects([data[0], ...projects]); // Update UI immediately
      setTitle("");
      setDescription("");
    }
  };

  const deleteProject = async (projectId) => {
    const confirmDelete = window.confirm(
      "Delete this project?\nThis action cannot be undone."
    );
    if (!confirmDelete) return;

    const { error } = await supabase
      .from("projects")
      .delete()
      .eq("id", projectId)
      .eq("user_id", user.id); // Extra safety layer

    if (error) {
      alert("Could not delete: " + error.message);
    } else {
      setProjects((prev) => prev.filter((p) => p.id !== projectId));
    }
  };

  if (loading) return <div className="profile-root">Loading...</div>;

  return (
    <>
      <style>{styles}</style>
      <div className="profile-root">
        <div className="profile-inner">
          <div className="profile-header">
            <h2>My Profile</h2>
            <div className="dot" />
          </div>

          {/* CREATE SECTION */}
          <div className="create-section">
            <p className="section-label">New Project</p>
            <div className="form-group">
              <input
                className="form-field"
                placeholder="Project title"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
              <textarea
                className="form-field"
                placeholder="Description"
                rows="3"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
            <button className="btn-create" onClick={createProject}>
              Create Project
            </button>
          </div>

          {/* PROJECTS LIST */}
          <div>
            <p className="section-label">My Projects ({projects.length})</p>
            <div className="projects-list">
              {projects.length === 0 ? (
                <p style={{ color: "var(--ink-muted)" }}>No projects yet.</p>
              ) : (
                projects.map((proj) => (
                  <div
                    key={proj.id}
                    className="project-card"
                    onClick={() => navigate(`/project/${proj.id}`)}
                  >
                    <button
                      className="delete-btn"
                      onClick={(e) => {
                        e.stopPropagation();
                        deleteProject(proj.id);
                      }}
                    >
                      Delete
                    </button>
                    <h4>{proj.title}</h4>
                    {proj.description && (
                      <p style={{ fontSize: "0.9rem", marginTop: "8px", color: "var(--ink-muted)" }}>
                        {proj.description}
                      </p>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
